defaultSettings.chartCode:
// Write JavaScript that returns an ECharts options object.
// Available variables:
//   dp[0].value, dp[1].value ...  - latest values (up to 4 datapoints)
//   dp[0].history   - {values: [], timestamps: []} buffered locally
//   dp[0].name      - datapoint address
//   animation, font, bgColor
//
// Example: Single line trend (uses first datapoint)

var data = [];
var d = dp[0];
if (d.history && d.history.timestamps) {
  data = d.history.timestamps.map(function(t, i) {
    return [t, d.history.values[i]];
  });
}

return {
  animation: animation,
  textStyle: { fontFamily: font },
  backgroundColor: bgColor,
  tooltip: { trigger: 'axis' },
  xAxis: { type: 'time' },
  yAxis: { type: 'value' },
  series: [{
    name: d.name || 'Value',
    type: 'line',
    data: data,
    smooth: true
  }]
};
